import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({ refreshKey = 0 }) {

  // TICKETS
  const [tickets, setTickets] = useState([]);

  // FILTER STATES
  const [ticketIdSearch, setTicketIdSearch] = useState('');
  const [departmentFilter, setDepartmentFilter] = useState('');
  const [divisionSearch, setDivisionSearch] = useState('');
  const [moduleFilter, setModuleFilter] = useState('');
  const [submoduleFilter, setSubmoduleFilter] = useState('');
  const [status, setStatus] = useState('');

  // DROPDOWN DATA
  const [departments, setDepartments] = useState([]);
  const [modules, setModules] = useState([]);
  const [submodules, setSubmodules] = useState([]);

  // PAGINATION
  const [page, setPage] = useState(1);
  const [count, setCount] = useState(0);
  const [nextPage, setNextPage] = useState(null);
  const [previousPage, setPreviousPage] = useState(null);

  // LOAD DROPDOWNS
  const loadDropdowns = async () => {
    try {
      const [deptRes, moduleRes, submoduleRes] =
        await Promise.all([
          api.get('/masters/departments/'),
          api.get('/masters/modules/'),
          api.get('/masters/submodules/'),
        ]);

      setDepartments(
        deptRes.data.results || deptRes.data || []
      );

      setModules(
        moduleRes.data.results || moduleRes.data || []
      );

      setSubmodules(
        submoduleRes.data.results || submoduleRes.data || []
      );

    } catch (err) {
      console.error('Failed to load dropdowns', err);
    }
  };

  // FILTER MODULES BY DEPARTMENT
  const filteredModules = modules.filter(
    (module) =>
      !departmentFilter ||
      String(module.department) ===
        String(departmentFilter)
  );

  // FILTER SUBMODULES BY MODULE
  const filteredSubmodules = submodules.filter(
    (submodule) =>
      !moduleFilter ||
      String(submodule.module) ===
        String(moduleFilter)
  );

  // LOAD TICKETS
  const loadTickets = async (pageNo = page) => {
    try {

      const params = {
        page: pageNo,
      };

      if (ticketIdSearch) {
        params.ticket_id = ticketIdSearch;
      }

      if (departmentFilter) {
        params.department = departmentFilter;
      }

      if (divisionSearch) {
        params.division = divisionSearch;
      }

      if (moduleFilter) {
        params.module = moduleFilter;
      }

      if (submoduleFilter) {
        params.submodule = submoduleFilter;
      }

      if (status) {
        params.status = status;
      }

      const res = await api.get('/tickets/', {
        params,
      });

      const data = res.data;

      setTickets(data.results || []);
      setCount(data.count || 0);
      setNextPage(data.next);
      setPreviousPage(data.previous);

    } catch (err) {
      console.error('Failed to load tickets', err);
    }
  };

  // INITIAL LOAD
  useEffect(() => {
    loadDropdowns();
  }, []);

  // RESET PAGE WHEN FILTER CHANGES
  useEffect(() => {
    setPage(1);
  }, [
    ticketIdSearch,
    departmentFilter,
    divisionSearch,
    moduleFilter,
    submoduleFilter,
    status
  ]);

  // LOAD TICKETS
  useEffect(() => {
    loadTickets(page);
  }, [
    refreshKey,
    page,
    ticketIdSearch,
    departmentFilter,
    divisionSearch,
    moduleFilter,
    submoduleFilter,
    status
  ]);

  // RESET FILTERS
  const handleResetFilters = () => {
    setTicketIdSearch('');
    setDepartmentFilter('');
    setDivisionSearch('');
    setModuleFilter('');
    setSubmoduleFilter('');
    setStatus('');
    setPage(1);
  };

  // EXPORT EXCEL
  const handleExport = async () => {
    try {

      const params = {};

      if (ticketIdSearch)
        params.ticket_id = ticketIdSearch;

      if (departmentFilter)
        params.department = departmentFilter;

      if (divisionSearch)
        params.division = divisionSearch;

      if (moduleFilter)
        params.module = moduleFilter;

      if (submoduleFilter)
        params.submodule = submoduleFilter;

      if (status)
        params.status = status;

      const res = await api.get(
        '/tickets/export_excel/',
        {
          params,
          responseType: 'blob',
        }
      );

      const url =
        window.URL.createObjectURL(
          new Blob([res.data])
        );

      const link =
        document.createElement('a');

      link.href = url;
      link.setAttribute(
        'download',
        'tickets.xlsx'
      );

      document.body.appendChild(link);
      link.click();
      link.remove();

    } catch (err) {
      console.error('Export failed', err);
    }
  };

  // TOTAL PAGES
  const totalPages =
    Math.ceil(count / 8);

  return (
    <div>

      {/* FILTERS */}
      <div className="row mb-3 g-2">

        {/* TICKET ID */}
        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Ticket ID"
            value={ticketIdSearch}
            onChange={(e) =>
              setTicketIdSearch(
                e.target.value
              )
            }
          />
        </div>

        {/* DEPARTMENT */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={departmentFilter}
            onChange={(e) => {
              setDepartmentFilter(
                e.target.value
              );
              setModuleFilter('');
              setSubmoduleFilter('');
            }}
          >
            <option value="">
              All Departments
            </option>

            {departments.map((dept) => (
              <option
                key={dept.id}
                value={dept.id}
              >
                {dept.department_name}
              </option>
            ))}
          </select>
        </div>

        {/* DIVISION */}
        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Division"
            value={divisionSearch}
            onChange={(e) =>
              setDivisionSearch(
                e.target.value
              )
            }
          />
        </div>

        {/* MODULE */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={moduleFilter}
            onChange={(e) => {
              setModuleFilter(
                e.target.value
              );
              setSubmoduleFilter('');
            }}
          >
            <option value="">
              All Modules
            </option>

            {filteredModules.map(
              (module) => (
                <option
                  key={module.id}
                  value={module.id}
                >
                  {module.module_name}
                </option>
              )
            )}
          </select>
        </div>

        {/* SUBMODULE */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={submoduleFilter}
            onChange={(e) =>
              setSubmoduleFilter(
                e.target.value
              )
            }
            disabled={!moduleFilter}
          >
            <option value="">
              All Submodules
            </option>

            {filteredSubmodules.map(
              (submodule) => (
                <option
                  key={submodule.id}
                  value={submodule.id}
                >
                  {submodule.submodule_name}
                </option>
              )
            )}
          </select>
        </div>

        {/* STATUS */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={status}
            onChange={(e) =>
              setStatus(
                e.target.value
              )
            }
          >
            <option value="">
              All Status
            </option>
            <option value="Open">
              Open
            </option>
            <option value="In Progress">
              In Progress
            </option>
            <option value="Resolved by Support">
              Resolved by Support
            </option>
            <option value="Sent to Developer">
              Sent to Developer
            </option>
            <option value="Developer In Progress">
              Developer In Progress
            </option>
            <option value="Closed">
              Closed
            </option>
            <option value="Reopened">
              Reopened
            </option>
          </select>
        </div>

        {/* RESET */}
        <div className="col-md-2 d-grid">
          <button
            className="btn btn-secondary"
            onClick={
              handleResetFilters
            }
          >
            Reset
          </button>
        </div>

        {/* EXPORT */}
        <div className="col-md-2 d-grid">
          <button
            className="btn btn-success"
            onClick={handleExport}
          >
            Export Excel
          </button>
        </div>

      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between mt-3">
        <button
          className="btn btn-outline-secondary"
          disabled={!previousPage}
          onClick={() =>
            setPage(
              (prev) => prev - 1
            )
          }
        >
          Previous
        </button>

        <span>
          Page {page} of{' '}
          {totalPages || 1}
        </span>

        <button
          className="btn btn-outline-secondary"
          disabled={!nextPage}
          onClick={() =>
            setPage(
              (prev) => prev + 1
            )
          }
        >
          Next
        </button>
      </div>
    </div>
  );
}
